INSERT INTO game_tbl (
	genre
	, price
	, img_url
	, name
	, grade
) VALUES (
	#{genre}
	, #{price}
	, #{imgUrl}
	, #{name}
	, #{grade}
)

mapper.update:
UPDATE game_tbl SET
	name = #{name}
	, price = #{price}
	, genre = #{genre}
	, img_url = #{imgUrl}
	, grade = #{grade}
WHERE id = #{id}

mapper.select:
SELECT count(*) AS cnt FROM game_tbl WHERE 1 = 1
AND name LIKE CONCAT('%', #{searchName}, '%')
AND grade = #{searchGrade}

SELECT id , name , genre , grade , price , img_url FROM game_tbl WHERE 1 = 1
AND name LIKE CONCAT('%', #{searchName}, '%')
AND grade = #{searchGrade}
ORDER BY id DESC LIMIT ${rowsPerPage} OFFSET #{curPage}
